import React, { createContext, useState, useContext, useEffect } from 'react';
import { authAPI } from '../utils/api';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      // For now, set a mock user until backend is connected
      setUser({ name: 'Demo User', email: 'demo@smartspend.com' });
      setLoading(false);
      
      // When backend is ready, uncomment this:
      // authAPI.verifyToken()
      //   .then(userData => setUser(userData))
      //   .catch(() => localStorage.removeItem('token'))
      //   .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (email, password) => {
    try {
      // Mock login for now - replace with actual API call
      const mockUser = { name: 'Demo User', email };
      const mockToken = 'mock-jwt-token';
      
      setUser(mockUser);
      localStorage.setItem('token', mockToken);
      
      return { user: mockUser, token: mockToken };
      
      // When backend is ready:
      // const response = await authAPI.login(email, password);
      // setUser(response.user);
      // localStorage.setItem('token', response.token);
      // return response;
    } catch (error) {
      throw error;
    }
  };

  const register = async (userData) => {
    try {
      // Mock registration for now
      const mockUser = { name: userData.name, email: userData.email };
      const mockToken = 'mock-jwt-token';
      
      setUser(mockUser);
      localStorage.setItem('token', mockToken);
      
      return { user: mockUser, token: mockToken };
      
      // When backend is ready:
      // const response = await authAPI.register(userData);
      // setUser(response.user);
      // localStorage.setItem('token', response.token);
      // return response;
    } catch (error) {
      throw error;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('token');
  };

  const value = {
    user,
    login,
    register,
    logout,
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}
export { AuthContext };
